export enum Grade {
  A = 'A',
  B = 'B',
  C = 'C',
}

export enum QualityLevel {
  Simple = 'Simple',
  Standard = 'Standard',
  HighQuality = 'High Quality',
  Special = 'Special',
}

export interface RateCardItem {
  id: string;
  name: string;
  category: string;
  // Prices are structured: [QualityLevel][Grade] -> number
  prices: {
    [key in QualityLevel]?: {
      [key in Grade]?: number;
    };
  };
  unit?: string;
  note?: string;
}

export interface LineItem {
  id: string; // Unique ID for the row in the invoice
  rateCardId: string;
  name: string;
  category: string;
  quality: QualityLevel;
  grade: Grade;
  quantity: number;
  unitPrice: number;
  total: number;
}

export interface CategoryGroup {
  name: string;
  items: RateCardItem[];
}

import { Grade, QualityLevel, RateCardItem, CategoryGroup } from '../types';

// Helper to generate a generic price structure for demonstration
// In a real scenario, these numbers would come exactly from the CSV columns
const generatePrices = (basePrice: number) => ({
  [QualityLevel.Simple]: {
    [Grade.C]: basePrice * 0.8,
    [Grade.B]: basePrice * 0.9,
    [Grade.A]: basePrice * 1.0,
  },
  [QualityLevel.Standard]: {
    [Grade.C]: basePrice * 1.2,
    [Grade.B]: basePrice * 1.35,
    [Grade.A]: basePrice * 1.5,
  },
  [QualityLevel.HighQuality]: {
    [Grade.C]: basePrice * 1.8,
    [Grade.B]: basePrice * 2.0,
    [Grade.A]: basePrice * 2.2,
  },
  [QualityLevel.Special]: {
    [Grade.C]: basePrice * 2.5,
    [Grade.B]: basePrice * 3.0,
    [Grade.A]: basePrice * 3.5,
  },
});

const generateItem = (id: string, name: string, category: string, basePrice: number, unit: string = 'Bài'): RateCardItem => ({
  id,
  name,
  category,
  prices: generatePrices(basePrice),
  unit,
});

