import React, { useState, useEffect } from 'react';
import { Plus, HelpCircle, Info } from 'lucide-react';
import { CATEGORIES, ALL_ITEMS } from '../services/mockData';
import { Grade, QualityLevel, RateCardItem } from '../types';

interface CalculatorFormProps {
  onAddItem: (item: RateCardItem, quality: QualityLevel, grade: Grade, quantity: number) => void;
}

const CalculatorForm: React.FC<CalculatorFormProps> = ({ onAddItem }) => {
  const [selectedCategory, setSelectedCategory] = useState<string>(CATEGORIES[0].name);
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [quality, setQuality] = useState<QualityLevel>(QualityLevel.Standard);
  const [grade, setGrade] = useState<Grade>(Grade.A);
  const [quantity, setQuantity] = useState<number>(1);
  const [currentPrice, setCurrentPrice] = useState<number>(0);

  // Filter items based on category
  const activeItems = CATEGORIES.find(c => c.name === selectedCategory)?.items || [];

  // Set default item when category changes
  useEffect(() => {
    if (activeItems.length > 0) {
      setSelectedItemId(activeItems[0].id);
    }
  }, [selectedCategory]);

  // Determine current price based on selection
  useEffect(() => {
    const item = activeItems.find(i => i.id === selectedItemId);
    if (item && item.prices[quality] && item.prices[quality]![grade]) {
      setCurrentPrice(item.prices[quality]![grade]!);
    } else {
      // Fallback logic as requested: map to Standard if not found, or 0
      const standardPrice = item?.prices[QualityLevel.Standard]?.[Grade.A];
      setCurrentPrice(standardPrice || 0);
    }
  }, [selectedItemId, quality, grade, activeItems]);

  const handleAdd = () => {
    const item = activeItems.find(i => i.id === selectedItemId);
    if (item) {
      onAddItem(item, quality, grade, quantity);
      // Optional: Reset quantity to 1 for quick next entry
      setQuantity(1);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(val);

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
      <div className="flex items-center gap-2 mb-6 border-b border-slate-100 pb-4">
        <div className="w-8 h-8 bg-brand-100 text-brand-600 rounded-lg flex items-center justify-center">
          <Plus size={20} />
        </div>
        <h2 className="text-lg font-semibold text-slate-800">Thêm hạng mục</h2>
      </div>

      <div className="space-y-5">
        {/* Category Selection */}
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Nhóm định dạng</label>
          <select 
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
            className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500 transition-colors"
          >
            {CATEGORIES.map(cat => (
              <option key={cat.name} value={cat.name}>{cat.name}</option>
            ))}
          </select>
        </div>

        {/* Item Selection */}
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Tên bài / Hạng mục</label>
          <select 
            value={selectedItemId}
            onChange={(e) => setSelectedItemId(e.target.value)}
            className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500 transition-colors"
          >
            {activeItems.map(item => (
              <option key={item.id} value={item.id}>{item.name}</option>
            ))}
          </select>
        </div>

        {/* Quality & Grade Grid */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Chất lượng (Level)</label>
            <select 
              value={quality}
              onChange={(e) => setQuality(e.target.value as QualityLevel)}
              className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500"
            >
              {Object.values(QualityLevel).map(q => (
                <option key={q} value={q}>{q}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Phân loại (Grade)</label>
            <div className="flex bg-slate-100 p-1 rounded-lg">
              {Object.values(Grade).map(g => (
                <button
                  key={g}
                  onClick={() => setGrade(g)}
                  className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${
                    grade === g 
                      ? 'bg-white text-brand-600 shadow-sm' 
                      : 'text-slate-500 hover:text-slate-700'
                  }`}
                >
                  {g}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Quantity & Preview */}
        <div className="flex items-end gap-4">
          <div className="w-1/3">
            <label className="block text-sm font-medium text-slate-700 mb-1">Số lượng</label>
            <input 
              type="number" 
              min="0.5"
              step="0.5"
              value={quantity}
              onChange={(e) => setQuantity(parseFloat(e.target.value) || 0)}
              className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500"
            />
          </div>

          <div className="flex-1 bg-brand-50 p-3 rounded-lg border border-brand-100 flex justify-between items-center">
            <div>
              <span className="text-xs text-brand-600 font-semibold block uppercase">Đơn giá ước tính</span>
              <span className="text-lg font-bold text-brand-900">{formatCurrency(currentPrice)}</span>
            </div>
             <div className="text-right">
              <span className="text-xs text-brand-600 font-semibold block uppercase">Thành tiền</span>
              <span className="text-lg font-bold text-brand-700">{formatCurrency(currentPrice * quantity)}</span>
            </div>
          </div>
        </div>

        {/* Info Note */}
        <div className="flex items-start gap-2 text-xs text-slate-500 bg-slate-50 p-3 rounded-md">
           <Info size={16} className="shrink-0 mt-0.5" />
           <p>
             Giá trị được lấy theo Rate Card 2024. Nếu hạng mục không có mức giá Simple/Special, hệ thống sẽ tự động map về Standard hoặc giá trị gần nhất.
           </p>
        </div>

        <button 
          onClick={handleAdd}
          className="w-full py-3 px-4 bg-brand-600 hover:bg-brand-700 text-white font-semibold rounded-lg shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
        >
          <Plus size={20} />
          Thêm vào danh sách
        </button>
      </div>
    </div>
  );
};

export default CalculatorForm;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { LineItem } from '../types';

interface DashboardProps {
  items: LineItem[];
}

const COLORS = ['#0ea5e9', '#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b'];

const Dashboard: React.FC<DashboardProps> = ({ items }) => {
  if (items.length === 0) return null;

  // Aggregate by Category
  const dataByCategory = items.reduce((acc, item) => {
    const existing = acc.find(d => d.name === item.category);
    if (existing) {
      existing.value += item.total;
    } else {
      acc.push({ name: item.category, value: item.total });
    }
    return acc;
  }, [] as { name: string; value: number }[]);

  // Aggregate by Grade
  const dataByGrade = items.reduce((acc, item) => {
     const existing = acc.find(d => d.name === `Grade ${item.grade}`);
    if (existing) {
      existing.value += item.total;
    } else {
      acc.push({ name: `Grade ${item.grade}`, value: item.total });
    }
    return acc;
  }, [] as { name: string; value: number }[]);


  const formatCurrencyShort = (val: number) => 
    (val / 1000000).toFixed(1) + 'M';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
      {/* Category Distribution */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-4">Phân bổ theo nhóm định dạng</h3>
        <div className="h-64 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={dataByCategory}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {dataByCategory.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip formatter={(value: number) => new Intl.NumberFormat('vi-VN').format(value) + ' VNĐ'} />
              <Legend verticalAlign="bottom" height={36}/>
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Grade Distribution */}
       <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-4">Giá trị theo Grade</h3>
        <div className="h-64 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={dataByGrade}
              layout="vertical"
              margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
            >
              <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
              <XAxis type="number" tickFormatter={formatCurrencyShort} hide />
              <YAxis dataKey="name" type="category" width={80} tick={{fontSize: 12}} />
              <Tooltip formatter={(value: number) => new Intl.NumberFormat('vi-VN').format(value) + ' VNĐ'} cursor={{fill: '#f1f5f9'}} />
              <Bar dataKey="value" fill="#0ea5e9" radius={[0, 4, 4, 0]} barSize={20} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Layers, Calculator, Github, HelpCircle, LayoutDashboard, List } from 'lucide-react';
import CalculatorForm from './components/CalculatorForm';
import InvoiceTable from './components/InvoiceTable';
import Dashboard from './components/Dashboard';
import { LineItem, RateCardItem, QualityLevel, Grade } from './types';

function App() {
  const [items, setItems] = useState<LineItem[]>([]);
  const [activeTab, setActiveTab] = useState<'calculator' | 'dashboard'>('calculator');

  const handleAddItem = (
    rateCardItem: RateCardItem, 
    quality: QualityLevel, 
    grade: Grade, 
    quantity: number
  ) => {
    // Determine price - fallback to 0 if not defined in map
    const price = rateCardItem.prices[quality]?.[grade] || 
                  rateCardItem.prices[QualityLevel.Standard]?.[Grade.A] || 0;

    const newItem: LineItem = {
      id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
      rateCardId: rateCardItem.id,
      name: rateCardItem.name,
      category: rateCardItem.category,
      quality,
      grade,
      quantity,
      unitPrice: price,
      total: price * quantity,
    };

    setItems(prev => [...prev, newItem]);
  };

  const handleRemoveItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const handleClear = () => {
    if (window.confirm("Bạn có chắc chắn muốn xóa toàn bộ danh sách?")) {
      setItems([]);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 font-sans text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-brand-600 p-2 rounded-lg text-white">
              <Calculator size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-900 leading-none">Admicro Royalty</h1>
              <span className="text-xs text-slate-500 font-medium">Calculator V3 - Rate Card 2024</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <nav className="hidden md:flex bg-slate-100 p-1 rounded-lg">
              <button 
                onClick={() => setActiveTab('calculator')}
                className={`px-4 py-1.5 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'calculator' ? 'bg-white text-brand-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
              >
                <List size={16} />
                Tính toán
              </button>
              <button 
                onClick={() => setActiveTab('dashboard')}
                className={`px-4 py-1.5 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'dashboard' ? 'bg-white text-brand-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
              >
                <LayoutDashboard size={16} />
                Thống kê
              </button>
            </nav>
            <div className="h-6 w-px bg-slate-200 hidden md:block"></div>
            <button className="text-slate-400 hover:text-slate-600">
              <HelpCircle size={20} />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">

        {activeTab === 'dashboard' && (
           <Dashboard items={items} />
        )}

        <div className={`flex flex-col lg:flex-row gap-8 items-start ${activeTab === 'dashboard' ? 'opacity-50 pointer-events-none filter grayscale' : ''}`}>

          {/* Left Column: Form */}
          <div className="w-full lg:w-1/3 space-y-6">
            <div className="lg:sticky lg:top-24">
              <CalculatorForm onAddItem={handleAddItem} />

              <div className="mt-6 bg-blue-50 border border-blue-100 rounded-xl p-4">
                 <h4 className="font-semibold text-blue-800 text-sm mb-2 flex items-center gap-2">
                   <Layers size={16}/> Nguyên tắc tính giá
                 </h4>
                 <ul className="text-xs text-blue-700 space-y-1.5 list-disc pl-4">
                   <li><strong>Simple:</strong> Cột C (Grade C, B, A tương ứng cột 5, 6, 7).</li>
                   <li><strong>Standard:</strong> Cột B (tương ứng cột 8, 9, 10).</li>
                   <li><strong>High Quality:</strong> Cột A (tương ứng cột 11, 12, 13).</li>
                   <li>Các hạng mục đặc biệt (Livestream, Pitching) có đơn giá riêng.</li>
                 </ul>
              </div>
            </div>
          </div>

          {/* Right Column: Invoice/Table */}
          <div className="w-full lg:w-2/3 h-full min-h-[500px]">
            <InvoiceTable 
              items={items} 
              onRemove={handleRemoveItem} 
              onClear={handleClear}
            />
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 mt-auto">
        <div className="max-w-7xl mx-auto px-4 py-6 flex flex-col md:flex-row justify-between items-center text-sm text-slate-500">
          <p>© 2024 Admicro Content Department. Internal Use Only.</p>
          <div className="flex items-center gap-1 mt-2 md:mt-0">
             <span>Version 3.0.1</span>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;

import { Grade, QualityLevel, RateCardItem, CategoryGroup } from '../types';

// Helper to generate a generic price structure
const generatePrices = (basePrice: number) => ({
  [QualityLevel.Simple]: {
    [Grade.C]: basePrice * 0.8,
    [Grade.B]: basePrice * 0.9,
    [Grade.A]: basePrice * 1.0,
  },
  [QualityLevel.Standard]: {
    [Grade.C]: basePrice * 1.2,
    [Grade.B]: basePrice * 1.35,
    [Grade.A]: basePrice * 1.5,
  },
  [QualityLevel.HighQuality]: {
    [Grade.C]: basePrice * 1.8,
    [Grade.B]: basePrice * 2.0,
    [Grade.A]: basePrice * 2.2,
  },
  [QualityLevel.Special]: {
    [Grade.C]: basePrice * 2.5,
    [Grade.B]: basePrice * 3.0,
    [Grade.A]: basePrice * 3.5,
  },
});

const createItem = (id: string, category: string, name: string, basePrice: number, unit: string = 'Bài'): RateCardItem => ({
  id,
  name,
  category,
  prices: generatePrices(basePrice),
  unit,
});

// Raw data list from the requirement
