import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { LineItem } from '../types';

interface DashboardProps {
  items: LineItem[];
}

const COLORS = ['#0ea5e9', '#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#14b8a6'];

const Dashboard: React.FC<DashboardProps> = ({ items }) => {
  if (items.length === 0) return null;

  const totalRevenue = items.reduce((sum, item) => sum + item.total, 0);

  // Helper to calculate percentage
  const toPercent = (value: number) => {
    if (totalRevenue === 0) return 0;
    return parseFloat(((value / totalRevenue) * 100).toFixed(1));
  };

  // Aggregate by Category
  const rawDataByCategory = items.reduce((acc, item) => {
    const existing = acc.find(d => d.name === item.category);
    if (existing) {
      existing.rawValue += item.total;
    } else {
      acc.push({ name: item.category, rawValue: item.total });
    }
    return acc;
  }, [] as { name: string; rawValue: number }[]);

  const dataByCategory = rawDataByCategory.map(d => ({
    name: d.name,
    value: toPercent(d.rawValue), // Convert to %
    amount: d.rawValue
  })).sort((a, b) => b.value - a.value);

  // Aggregate by Grade
  const rawDataByGrade = items.reduce((acc, item) => {
     const existing = acc.find(d => d.name === `Grade ${item.grade}`);
    if (existing) {
      existing.rawValue += item.total;
    } else {
      acc.push({ name: `Grade ${item.grade}`, rawValue: item.total });
    }
    return acc;
  }, [] as { name: string; rawValue: number }[]);

  const dataByGrade = rawDataByGrade.map(d => ({
    name: d.name,
    value: toPercent(d.rawValue), // Convert to %
    amount: d.rawValue
  })).sort((a, b) => b.name.localeCompare(a.name));


  const formatPercent = (val: number) => `${val}%`;

  // Custom Tooltip to show both % and Value
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div className="bg-white p-3 border border-slate-200 shadow-lg rounded-lg text-sm">
          <p className="font-semibold text-slate-800">{data.name}</p>
          <p className="text-brand-600 font-bold">{data.value}%</p>
          <p className="text-slate-500 text-xs">
            {new Intl.NumberFormat('vi-VN').format(data.amount)} VNĐ
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
      {/* Category Distribution */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-4">Tỷ trọng theo nhóm (%)</h3>
        <div className="h-64 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={dataByCategory}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {dataByCategory.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip content={<CustomTooltip />} />
              <Legend verticalAlign="bottom" height={36} iconType="circle"/>
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Grade Distribution */}
       <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-4">Tỷ trọng theo Grade (%)</h3>
        <div className="h-64 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={dataByGrade}
              layout="vertical"
              margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
            >
              <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
              <XAxis type="number" tickFormatter={formatPercent} domain={[0, 'auto']} />
              <YAxis dataKey="name" type="category" width={80} tick={{fontSize: 12}} />
              <Tooltip content={<CustomTooltip />} cursor={{fill: '#f1f5f9'}} />
              <Bar dataKey="value" fill="#0ea5e9" radius={[0, 4, 4, 0]} barSize={20} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

